```src/provider/aws.rs
use std::env;
use std::fs;
use std::io::{BufRead, Write, stdin, stdout};

use serde_json::Value;
use sha2::{Digest, Sha256};

use crate::utils::prompt_yes_no;

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

#[derive(Debug, Clone)]
pub struct AwsEntry {
    pub access_key_id: String,
    pub secret_access_key: String,
    pub region: String,
    /// Availability zone, e.g. "us-east-1a"
    pub zone: String,
}

// ---------------------------------------------------------------------------
// Minimal HMAC-SHA256 (no extra crate needed)
// ---------------------------------------------------------------------------

fn hmac_sha256(key: &[u8], data: &[u8]) -> Vec<u8> {
    const BLOCK: usize = 64;

    let mut k = if key.len() > BLOCK {
        Sha256::digest(key).to_vec()
    } else {
        key.to_vec()
    };
    k.resize(BLOCK, 0);

    let ipad: Vec<u8> = k.iter().map(|b| b ^ 0x36).collect();
    let opad: Vec<u8> = k.iter().map(|b| b ^ 0x5c).collect();

    let mut inner = Sha256::new();
    inner.update(&ipad);
    inner.update(data);
    let inner_hash = inner.finalize();

    let mut outer = Sha256::new();
    outer.update(&opad);
    outer.update(&inner_hash);
    outer.finalize().to_vec()
}

fn hex(bytes: &[u8]) -> String {
    bytes.iter().map(|b| format!("{b:02x}")).collect()
}

fn sha256_hex(data: &[u8]) -> String {
    hex(&Sha256::digest(data))
}

// ---------------------------------------------------------------------------
// AWS Signature Version 4
// ---------------------------------------------------------------------------

/// Returns an `Authorization` header value for the given EC2 request.
///
/// `params` must already be sorted (use `build_sorted_params`).
fn sigv4_authorization(
    aws: &AwsEntry,
    method: &str,
    params: &str,   // pre-sorted URL-encoded query string
    payload: &str,  // request body ("" for GET)
    datetime: &str, // e.g. "20240101T120000Z"
    date: &str,     // e.g. "20240101"
) -> String {
    let service = "ec2";
    let host = format!("ec2.{}.amazonaws.com", aws.region);
    let payload_hash = sha256_hex(payload.as_bytes());

    // ── Canonical request ─────────────────────────────────────────────────
    let canonical_headers = format!("host:{host}\nx-amz-date:{datetime}\n");
    let signed_headers = "host;x-amz-date";
    let canonical_request = format!(
        "{method}\n/\n{params}\n{canonical_headers}\n{signed_headers}\n{payload_hash}"
    );

    // ── String to sign ────────────────────────────────────────────────────
    let credential_scope = format!("{date}/{}/{service}/aws4_request", aws.region);
    let string_to_sign = format!(
        "AWS4-HMAC-SHA256\n{datetime}\n{credential_scope}\n{}",
        sha256_hex(canonical_request.as_bytes())
    );

    // ── Signing key ───────────────────────────────────────────────────────
    let k_date = hmac_sha256(
        format!("AWS4{}", aws.secret_access_key).as_bytes(),
        date.as_bytes(),
    );
    let k_region = hmac_sha256(&k_date, aws.region.as_bytes());
    let k_service = hmac_sha256(&k_region, service.as_bytes());
    let k_signing = hmac_sha256(&k_service, b"aws4_request");
    let signature = hex(&hmac_sha256(&k_signing, string_to_sign.as_bytes()));

    format!(
        "AWS4-HMAC-SHA256 Credential={}/{credential_scope}, \
         SignedHeaders={signed_headers}, Signature={signature}",
        aws.access_key_id
    )
}

// ---------------------------------------------------------------------------
// Current UTC helpers (no chrono needed — time crate already in tree)
// ---------------------------------------------------------------------------

fn utc_datetime_strings() -> (String, String) {
    let now = time::OffsetDateTime::now_utc();
    let datetime = format!(
        "{:04}{:02}{:02}T{:02}{:02}{:02}Z",
        now.year(),
        now.month() as u8,
        now.day(),
        now.hour(),
        now.minute(),
        now.second(),
    );
    let date = &datetime[..8];
    (datetime.clone(), date.to_string())
}

// ---------------------------------------------------------------------------
// Minimal URL encoding (only what EC2 query params need)
// ---------------------------------------------------------------------------

fn url_encode(s: &str) -> String {
    let mut out = String::new();
    for b in s.bytes() {
        match b {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'_' | b'.' | b'~' => {
                out.push(b as char);
            }
            _ => out.push_str(&format!("%{b:02X}")),
        }
    }
    out
}

/// Build a sorted, URL-encoded EC2 query string from key-value pairs.
fn build_sorted_params(mut pairs: Vec<(&str, String)>) -> String {
    // EC2 SigV4 requires lexicographic ordering by encoded key name.
    pairs.sort_by(|a, b| a.0.cmp(b.0));
    pairs
        .iter()
        .map(|(k, v)| format!("{}={}", url_encode(k), url_encode(v)))
        .collect::<Vec<_>>()
        .join("&")
}

// ---------------------------------------------------------------------------
// HTTP helper — signed EC2 GET request
// ---------------------------------------------------------------------------

fn ec2_get(aws: &AwsEntry, params: Vec<(&str, String)>) -> Result<String, Box<dyn std::error::Error>> {
    let (datetime, date) = utc_datetime_strings();
    let sorted = build_sorted_params(params);
    let auth = sigv4_authorization(aws, "GET", &sorted, "", &datetime, &date);

    let url = format!("https://ec2.{}.amazonaws.com/?{sorted}", aws.region);

    let agent: ureq::Agent = ureq::Agent::config_builder()
        .http_status_as_error(false)
        .build()
        .into();

    let mut resp = agent
        .get(&url)
        .header("Authorization", &auth)
        .header("x-amz-date", &datetime)
        .call()?;

    let status = resp.status();
    let body = resp.body_mut().read_to_string()?;

    if !status.is_success() {
        return Err(format!("EC2 API returned HTTP {status}:\n{body}").into());
    }

    Ok(body)
}

// ---------------------------------------------------------------------------
// Minimal XML text extractor (no extra crate needed)
// ---------------------------------------------------------------------------

/// Returns the first occurrence of the text content inside `<tag>…</tag>`.
fn xml_first(xml: &str, tag: &str) -> Option<String> {
    let open = format!("<{tag}>");
    let close = format!("</{tag}>");
    let start = xml.find(&open)? + open.len();
    let end = xml[start..].find(&close)? + start;
    Some(xml[start..end].trim().to_string())
}

/// Returns all occurrences of the text content inside `<tag>…</tag>`.
fn xml_all<'a>(xml: &'a str, tag: &str) -> Vec<&'a str> {
    let open = format!("<{tag}>");
    let close = format!("</{tag}>");
    let mut results = Vec::new();
    let mut remaining = xml;
    loop {
        let Some(s) = remaining.find(&open) else {
            break;
        };
        let after = &remaining[s + open.len()..];
        let Some(e) = after.find(&close) else {
            break;
        };
        results.push(after[..e].trim());
        remaining = &after[e + close.len()..];
    }
    results
}

// ---------------------------------------------------------------------------
// Compute — RunInstances (create)
// ---------------------------------------------------------------------------

/// `ssh_public_key` is the raw public key text (not "user:key" format).
/// It is injected via UserData so the `ubuntu` user can connect without a
/// pre-created EC2 key-pair.
#[allow(clippy::too_many_arguments)]
pub fn create_vm(
    aws: &AwsEntry,
    instance_name: &str,
    instance_type: &str,
    ami_id: &str,
    boot_disk_size_gb: u64,
    ssh_public_key: &str,
    startup_script: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    use base64::Engine;

    // Build a UserData script that appends the public key *and* runs the
    // caller's startup script, matching the GCP metadata approach.
    let user_data_script = format!(
        "#!/bin/bash\nset -e\n\
         # Inject SSH public key for the ubuntu user\n\
         mkdir -p /home/ubuntu/.ssh\n\
         echo '{ssh_public_key}' >> /home/ubuntu/.ssh/authorized_keys\n\
         chmod 700 /home/ubuntu/.ssh\n\
         chmod 600 /home/ubuntu/.ssh/authorized_keys\n\
         chown -R ubuntu:ubuntu /home/ubuntu/.ssh\n\n\
         # Caller startup script\n\
         {startup_script}\n"
    );

    let user_data_b64 =
        base64::engine::general_purpose::STANDARD.encode(user_data_script.as_bytes());

    let (datetime, date) = utc_datetime_strings();

    let mut pairs: Vec<(&str, String)> = vec![
        ("Action", "RunInstances".into()),
        ("ImageId", ami_id.into()),
        ("InstanceType", instance_type.into()),
        ("MaxCount", "1".into()),
        ("MinCount", "1".into()),
        ("Placement.AvailabilityZone", aws.zone.clone()),
        ("TagSpecification.1.ResourceType", "instance".into()),
        ("TagSpecification.1.Tag.1.Key", "Name".into()),
        ("TagSpecification.1.Tag.1.Value", instance_name.into()),
        (
            "BlockDeviceMapping.1.DeviceName",
            "/dev/sda1".into(),
        ),
        (
            "BlockDeviceMapping.1.Ebs.VolumeSize",
            boot_disk_size_gb.to_string(),
        ),
        (
            "BlockDeviceMapping.1.Ebs.VolumeType",
            "gp3".into(),
        ),
        (
            "BlockDeviceMapping.1.Ebs.DeleteOnTermination",
            "true".into(),
        ),
        ("UserData", user_data_b64),
        ("Version", "2016-11-15".into()),
    ];

    let sorted = build_sorted_params(pairs);
    let auth = sigv4_authorization(aws, "GET", &sorted, "", &datetime, &date);

    let url = format!("https://ec2.{}.amazonaws.com/?{sorted}", aws.region);

    let agent: ureq::Agent = ureq::Agent::config_builder()
        .http_status_as_error(false)
        .build()
        .into();

    let mut resp = agent
        .get(&url)
        .header("Authorization", &auth)
        .header("x-amz-date", &datetime)
        .call()?;

    let status = resp.status();
    let body = resp.body_mut().read_to_string()?;

    if !status.is_success() {
        return Err(format!(
            "EC2 RunInstances returned HTTP {status} for '{instance_name}':\n{body}"
        )
        .into());
    }

    // Return a JSON-style summary so callers can pretty-print it uniformly.
    let instance_id = xml_first(&body, "instanceId").unwrap_or_else(|| "(unknown)".into());
    let state = xml_first(&body, "name").unwrap_or_else(|| "(unknown)".into());

    let summary = serde_json::json!({
        "instanceId":   instance_id,
        "instanceName": instance_name,
        "instanceType": instance_type,
        "ami":          ami_id,
        "zone":         aws.zone,
        "state":        state,
    });

    Ok(serde_json::to_string_pretty(&summary)?)
}

// ---------------------------------------------------------------------------
// Compute — TerminateInstances (delete)
// ---------------------------------------------------------------------------

/// Terminate by EC2 instance ID.  Call `get_instance_id_by_name` first.
pub fn delete_vm(
    aws: &AwsEntry,
    instance_id: &str,
    instance_name: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let xml = ec2_get(
        aws,
        vec![
            ("Action", "TerminateInstances".into()),
            ("InstanceId.1", instance_id.into()),
            ("Version", "2016-11-15".into()),
        ],
    )?;

    let current = xml_first(&xml, "name").unwrap_or_else(|| "(unknown)".into());
    let previous = xml_first(&xml, "previousState")
        .and_then(|s| {
            // <previousState><code>16</code><name>running</name></previousState>
            // xml_first operates on the full doc so we just re-extract from the
            // previousState substring
            let tag = "name";
            let start_tag = format!("<{tag}>");
            let end_tag = format!("</{tag}>");
            // Find the second occurrence (first is inside currentState)
            let first = s.find(&start_tag)? + start_tag.len();
            let after = &s[first..];
            let end = after.find(&end_tag)?;
            Some(after[..end].trim().to_string())
        })
        .unwrap_or_else(|| "(unknown)".into());

    let summary = serde_json::json!({
        "instanceId":    instance_id,
        "instanceName":  instance_name,
        "currentState":  current,
        "previousState": previous,
    });

    Ok(serde_json::to_string_pretty(&summary)?)
}

// ---------------------------------------------------------------------------
// Compute — DescribeInstances helpers
// ---------------------------------------------------------------------------

/// Look up an EC2 instance by its `Name` tag and return `(instance_id, private_ip)`.
pub fn describe_instance(
    aws: &AwsEntry,
    instance_name: &str,
) -> Result<(String, String), Box<dyn std::error::Error>> {
    let xml = ec2_get(
        aws,
        vec![
            ("Action", "DescribeInstances".into()),
            ("Filter.1.Name", "tag:Name".into()),
            ("Filter.1.Value.1", instance_name.into()),
            ("Filter.2.Name", "instance-state-name".into()),
            ("Filter.2.Value.1", "running".into()),
            ("Version", "2016-11-15".into()),
        ],
    )?;

    let instance_id = xml_first(&xml, "instanceId").ok_or_else(|| {
        format!("No running instance named '{instance_name}' found in {}", aws.region)
    })?;

    let private_ip = xml_first(&xml, "privateIpAddress").ok_or_else(|| {
        format!("Instance '{instance_name}' ({instance_id}) has no private IP yet")
    })?;

    Ok((instance_id, private_ip))
}

// ---------------------------------------------------------------------------
// Credential builder
// ---------------------------------------------------------------------------

pub fn print_build_credential() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== Maglev AWS Credential Builder ===\n");

    // Try to load from environment first.
    let from_env = try_load_from_env();

    let (access_key_id, secret_access_key, region) = match from_env {
        Some(triple) => {
            println!("  Loaded credentials from environment variables.\n");
            triple
        }
        None => {
            println!("  AWS_ACCESS_KEY_ID / AWS_SECRET_ACCESS_KEY not set — prompting.\n");
            prompt_credentials()?
        }
    };

    println!("\n── Credential summary ──────────────────────────────────────────────────\n");
    println!("  Access Key ID : {access_key_id}");
    println!("  Region        : {region}");
    println!("  Secret Key    : {}", "*".repeat(secret_access_key.len().min(40)));

    println!("\n  You can store these in a .env file or export them:\n");
    println!("    export AWS_ACCESS_KEY_ID={access_key_id}");
    println!("    export AWS_SECRET_ACCESS_KEY=<your-secret>");
    println!("    export MAGLEV_AWS_REGION={region}");

    if prompt_yes_no("\nSave credentials to .maglev-aws-credentials?") {
        let content = format!(
            "AWS_ACCESS_KEY_ID={access_key_id}\n\
             AWS_SECRET_ACCESS_KEY={secret_access_key}\n\
             MAGLEV_AWS_REGION={region}\n"
        );
        fs::write(".maglev-aws-credentials", &content)
            .map_err(|e| format!("Cannot write credentials file: {e}"))?;
        println!("✓ Saved to .maglev-aws-credentials");
        println!("⚠  Keep this file secure and do not commit it to version control.");
    }

    // Verify credentials with a lightweight DescribeRegions call.
    if prompt_yes_no("\nVerify credentials with a test API call (DescribeRegions)?") {
        verify_credentials(&access_key_id, &secret_access_key, &region)?;
    }

    Ok(())
}

fn try_load_from_env() -> Option<(String, String, String)> {
    let id = env::var("AWS_ACCESS_KEY_ID").ok()?;
    let secret = env::var("AWS_SECRET_ACCESS_KEY").ok()?;
    let region = env::var("MAGLEV_AWS_REGION")
        .or_else(|_| env::var("AWS_DEFAULT_REGION"))
        .unwrap_or_else(|_| "us-east-1".to_string());
    Some((id, secret, region))
}

fn prompt_credentials() -> Result<(String, String, String), Box<dyn std::error::Error>> {
    let access_key_id = prompt_line("  AWS Access Key ID: ")?;
    let secret_access_key = prompt_line("  AWS Secret Access Key: ")?;
    let region_input = prompt_line("  AWS Region [us-east-1]: ")?;
    let region = if region_input.is_empty() {
        "us-east-1".to_string()
    } else {
        region_input
    };
    Ok((access_key_id, secret_access_key, region))
}

fn prompt_line(msg: &str) -> Result<String, Box<dyn std::error::Error>> {
    print!("{msg}");
    stdout().flush()?;
    let mut line = String::new();
    stdin().lock().read_line(&mut line)?;
    Ok(line.trim().to_string())
}

fn verify_credentials(
    access_key_id: &str,
    secret_access_key: &str,
    region: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let aws = AwsEntry {
        access_key_id: access_key_id.to_string(),
        secret_access_key: secret_access_key.to_string(),
        region: region.to_string(),
        zone: format!("{region}a"),
    };

    let xml = ec2_get(
        &aws,
        vec![
            ("Action", "DescribeAvailabilityZones".into()),
            ("Version", "2016-11-15".into()),
        ],
    )?;

    let zones = xml_all(&xml, "zoneName");
    if zones.is_empty() {
        return Err("Verification call succeeded but returned no availability zones.".into());
    }

    println!("\n  ✓ Credentials valid.  Availability zones visible:");
    for z in &zones {
        println!("      {z}");
    }

    Ok(())
}
