        match self {
            CloudProvider::Gcp(_) => "GCP",
            CloudProvider::Aws(_) => "AWS",
        }
    }
}

#[derive(Debug)]
struct MaglevConfig {
    name: String,
    control_planes: Vec<NodeEntry>,
    node_pool: NodePoolEntry,
    cloud: CloudProvider,
}

// ---------------------------------------------------------------------------
// JWT / OAuth2 (GCP only)
// ---------------------------------------------------------------------------

fn b64url(input: &[u8]) -> String {
    use base64::Engine;
    base64::engine::general_purpose::URL_SAFE_NO_PAD.encode(input)
}

fn create_jwt(
    private_key_pem: &str,
    client_email: &str,
    scope: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    use rsa::{pkcs1v15::Pkcs1v15Sign, pkcs8::DecodePrivateKey, RsaPrivateKey};
    use sha2::{Digest, Sha256};

    let private_key = RsaPrivateKey::from_pkcs8_pem(private_key_pem)?;
    let now = time::OffsetDateTime::now_utc().unix_timestamp();
    let exp = now + 3600;

    let header = r#"{"alg":"RS256","typ":"JWT"}"#;
    let claims = format!(
        r#"{{"iss":"{}","scope":"{}","aud":"https://oauth2.googleapis.com/token","exp":{},"iat":{}}}"#,
        client_email, scope, exp, now
    );

    let signing_input = format!(
        "{}.{}",
        b64url(header.as_bytes()),
        b64url(claims.as_bytes())
    );
    let hash = Sha256::digest(signing_input.as_bytes());

    const SHA256_DIGEST_INFO: [u8; 19] = [
        0x30, 0x31, 0x30, 0x0d, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x02, 0x01,
        0x05, 0x00, 0x04, 0x20,
    ];
    let mut to_sign = Vec::with_capacity(SHA256_DIGEST_INFO.len() + hash.len());
    to_sign.extend_from_slice(&SHA256_DIGEST_INFO);
    to_sign.extend_from_slice(&hash);

    let signature = private_key.sign(Pkcs1v15Sign::new_unprefixed(), &to_sign)?;
    Ok(format!("{}.{}", signing_input, b64url(&signature)))
}

fn get_access_token(jwt: &str) -> Result<String, Box<dyn std::error::Error>> {
    let agent: ureq::Agent = ureq::Agent::config_builder()
        .http_status_as_error(false)
        .build()
        .into();

    let mut resp = agent
        .post("https://oauth2.googleapis.com/token")
        .send_form([
            ("grant_type", "urn:ietf:params:oauth:grant-type:jwt-bearer"),
            ("assertion", jwt),
        ])?;

    let status = resp.status();
    let body: Value = resp.body_mut().read_json()?;

    if !status.is_success() {
        return Err(format!("Token endpoint returned HTTP {status}: {body}").into());
    }

    body["access_token"]
        .as_str()
        .map(|s| s.to_string())
        .ok_or_else(|| format!("No access_token in response: {body}").into())
}

// ---------------------------------------------------------------------------
// GCP — fetch internal IP
// ---------------------------------------------------------------------------

fn get_gcp_vm_ip(
    access_token: &str,
    project_id: &str,
    zone: &str,
    instance_name: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let url = format!(
        "https://compute.googleapis.com/compute/v1/projects/{project_id}/zones/{zone}/instances/{instance_name}"
    );

    let agent: ureq::Agent = ureq::Agent::config_builder()
        .http_status_as_error(false)
        .build()
        .into();

    let mut resp = agent
        .get(&url)
        .header("Authorization", &format!("Bearer {access_token}"))
        .call()?;

    let status = resp.status();
    let body: Value = resp.body_mut().read_json()?;

    if !status.is_success() {
        return Err(format!(
            "Compute Engine API returned HTTP {status} for '{instance_name}': {body}"
        )
        .into());
    }

    body["networkInterfaces"][0]["networkIP"]
        .as_str()
        .map(|s| s.to_string())
        .ok_or_else(|| format!("No internal IP for '{instance_name}'").into())
}

// ---------------------------------------------------------------------------
// SSH helpers
// ---------------------------------------------------------------------------

fn ssh_capture(
    ip: &str,
    user: &str,
    private_key_path: &str,
    command: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let out = std::process::Command::new("ssh")
        .args([
            "-i", private_key_path,
            "-o", "StrictHostKeyChecking=no",
            "-o", "UserKnownHostsFile=/dev/null",
            "-o", "ConnectTimeout=15",
            "-o", "LogLevel=ERROR",
            &format!("{user}@{ip}"),
            command,
        ])
        .output()
        .map_err(|e| format!("Failed to spawn ssh: {e}"))?;

    if !out.status.success() {
        let stderr = String::from_utf8_lossy(&out.stderr);
        return Err(format!(
            "ssh capture exited {} — {stderr}",
            out.status.code().unwrap_or(-1)
        )
        .into());
    }

    Ok(String::from_utf8_lossy(&out.stdout).trim().to_string())
}

fn ssh_run(
    ip: &str,
    user: &str,
    private_key_path: &str,
    command: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let status = std::process::Command::new("ssh")
        .args([
            "-i", private_key_path,
            "-o", "StrictHostKeyChecking=no",
            "-o", "UserKnownHostsFile=/dev/null",
            "-o", "ConnectTimeout=30",
            "-o", "LogLevel=ERROR",
            "-t",
            &format!("{user}@{ip}"),
            command,
        ])
        .status()
        .map_err(|e| format!("Failed to spawn ssh: {e}"))?;

    if !status.success() {
        return Err(format!(
            "Remote command exited {}",
            status.code().unwrap_or(-1)
        )
        .into());
    }

    Ok(())
}

// ---------------------------------------------------------------------------
// HCL config — helpers
// ---------------------------------------------------------------------------

fn expr_to_string(expr: &hcl::Expression) -> Option<String> {
    match expr {
        hcl::Expression::String(s) => Some(s.clone()),
        hcl::Expression::Number(n) => Some(n.to_string()),
        hcl::Expression::Bool(b) => Some(b.to_string()),
        _ => None,
    }
}

fn block_attrs(body: &hcl::Body) -> HashMap<String, String> {
    body.attributes()
        .filter_map(|a| expr_to_string(a.expr()).map(|v| (a.key().to_string(), v)))
        .collect()
}

fn parse_worker_node_block(block: &hcl::Block) -> Result<NodeEntry, Box<dyn std::error::Error>> {
    let labels = block.labels();
    let instance_name = labels
        .get(1)
        .map(|l| l.as_str().to_string())
        .ok_or("Worker 'node' block is missing its instance-name label")?;

    let attrs = block_attrs(block.body());

    Ok(NodeEntry {
        instance_name,
        ssh_public_key_path: attrs
            .get("ssh_public_key_path")
            .cloned()
            .unwrap_or_else(|| "~/.ssh/id_ed25519.pub".to_string()),
        startup_script_path: attrs
            .get("startup_script_path")
            .cloned()
            .unwrap_or_else(|| "./startup.sh".to_string()),
        boot_disk_image: None,
        boot_disk_size_gb: None,
        machine_type: None,
    })
}

// ---------------------------------------------------------------------------
// HCL config — parser
// ---------------------------------------------------------------------------

fn parse_maglev_config(content: &str) -> Result<MaglevConfig, Box<dyn std::error::Error>> {
    let body = hcl::parse(content).map_err(|e| format!("HCL parse error: {e}"))?;

    let maglev_block = body
        .blocks()
        .find(|b| b.identifier() == "maglev")
        .ok_or("No 'maglev' block found")?;

    let name = maglev_block
        .labels()
        .first()
        .map(|l| l.as_str().to_string())
        .unwrap_or_else(|| "maglev".to_string());

    let mut control_planes: Vec<NodeEntry> = Vec::new();
    let mut node_pool: Option<NodePoolEntry> = None;
    let mut gcp: Option<GcpEntry> = None;
    let mut aws: Option<AwsEntry> = None;

    for block in maglev_block.body().blocks() {
        match block.identifier() {
            "node" => {
                let labels = block.labels();
                let role = labels
                    .first()
                    .map(|l| l.as_str())
                    .ok_or("'node' block missing role label")?;

                if role != "control_plane" {
                    return Err(format!(
                        "Top-level 'node \"{role}\"' is not allowed; \
                         only 'control_plane' nodes live at the top level"
                    )
                    .into());
                }

                let instance_name = labels
                    .get(1)
                    .map(|l| l.as_str().to_string())
                    .ok_or("'node \"control_plane\"' missing instance-name label")?;

                let attrs = block_attrs(block.body());
                control_planes.push(NodeEntry {
                    instance_name,
                    ssh_public_key_path: attrs
                        .get("ssh_public_key_path")
                        .cloned()
                        .unwrap_or_else(|| "~/.ssh/id_ed25519.pub".to_string()),
                    startup_script_path: attrs
                        .get("startup_script_path")
                        .cloned()
                        .unwrap_or_else(|| "./startup-cp.sh".to_string()),
                    boot_disk_image: attrs.get("boot_disk_image").cloned(),
                    boot_disk_size_gb: attrs
                        .get("boot_disk_size_gb")
                        .and_then(|v| v.parse().ok()),
                    machine_type: attrs.get("machine_type").cloned(),
                });
            }

            "node_pool" => {
                let attrs = block_attrs(block.body());
                let pool_size: u64 = attrs
                    .get("boot_disk_size_gb")
                    .and_then(|v| v.parse().ok())
                    .unwrap_or(50);

                let mut workers: Vec<NodeEntry> = Vec::new();
                for inner in block.body().blocks() {
                    if inner.identifier() == "node" {
                        workers.push(parse_worker_node_block(inner)?);
                    } else {
                        eprintln!(
                            "  ⚠  Unknown block '{}' inside node_pool — skipping.",
                            inner.identifier()
                        );
                    }
                }

                node_pool = Some(NodePoolEntry {
                    boot_disk_image: attrs
                        .get("boot_disk_image")
                        .cloned()
                        .unwrap_or_else(|| "ubuntu-2404-lts-amd64".to_string()),
                    boot_disk_size_gb: pool_size,
                    machine_type: attrs
                        .get("machine_type")
                        .cloned()
                        .unwrap_or_else(|| "e2-standard-2".to_string()),
                    name: attrs.get("name").cloned().unwrap_or_else(|| name.clone()),
                    workers,
                });
            }

            "gcp_config" => {
                let attrs = block_attrs(block.body());
                let req = |key: &str| -> Result<String, Box<dyn std::error::Error>> {
                    attrs
                        .get(key)
                        .cloned()
                        .ok_or_else(|| format!("Missing '{key}' in gcp_config").into())
                };
                gcp = Some(GcpEntry {
                    client_email: req("client_email")?,
                    private_key: req("private_key")?,
                    project_id: req("project_id")?,
                    zone: req("zone")?,
                });
            }

            "aws_config" => {
                let attrs = block_attrs(block.body());
                let req = |key: &str| -> Result<String, Box<dyn std::error::Error>> {
                    attrs
                        .get(key)
                        .cloned()
                        .ok_or_else(|| format!("Missing '{key}' in aws_config").into())
                };
                aws = Some(AwsEntry {
                    access_key_id: req("access_key_id")?,
                    secret_access_key: req("secret_access_key")?,
                    region: req("region")?,
                    zone: req("zone")?,
                });
            }

            other => {
                eprintln!("  ⚠  Unknown block '{other}' — skipping.");
            }
        }
    }

    if control_planes.is_empty() {
        return Err("Config contains no 'node \"control_plane\" …' blocks".into());
    }
    let pool = node_pool.ok_or("Missing 'node_pool' block")?;
    if pool.workers.is_empty() {
        return Err("node_pool contains no 'node \"worker\" …' blocks".into());
    }

    // Prefer GCP if both are somehow present; otherwise require exactly one.
    let cloud = match (gcp, aws) {
        (Some(g), _) => CloudProvider::Gcp(g),
        (None, Some(a)) => CloudProvider::Aws(a),
        (None, None) => {
            return Err(
                "Config must contain either a 'gcp_config' block or an 'aws_config' block".into(),
            )
        }
    };

    Ok(MaglevConfig {
        name,
        control_planes,
        node_pool: pool,
        cloud,
    })
}

// ---------------------------------------------------------------------------
// HCL config — serialiser
// ---------------------------------------------------------------------------

fn build_control_plane_block(entry: &NodeEntry) -> hcl::Block {
    let mut b = hcl::Block::builder("node")
        .add_label("control_plane")
        .add_label(&entry.instance_name)
        .add_attribute(("ssh_public_key_path", entry.ssh_public_key_path.as_str()))
        .add_attribute(("startup_script_path", entry.startup_script_path.as_str()));

    if let Some(ref img) = entry.boot_disk_image {
        b = b.add_attribute(("boot_disk_image", img.as_str()));
    }
    if let Some(size) = entry.boot_disk_size_gb {
        b = b.add_attribute(("boot_disk_size_gb", size));
    }
    if let Some(ref mt) = entry.machine_type {
        b = b.add_attribute(("machine_type", mt.as_str()));
    }
    b.build()
}

fn build_worker_block(entry: &NodeEntry) -> hcl::Block {
    hcl::Block::builder("node")
        .add_label("worker")
        .add_label(&entry.instance_name)
        .add_attribute(("ssh_public_key_path", entry.ssh_public_key_path.as_str()))
        .add_attribute(("startup_script_path", entry.startup_script_path.as_str()))
        .build()
}

fn build_node_pool_block(pool: &NodePoolEntry) -> hcl::Block {
    let mut b = hcl::Block::builder("node_pool")
        .add_attribute(("boot_disk_image", pool.boot_disk_image.as_str()))
        .add_attribute(("boot_disk_size_gb", pool.boot_disk_size_gb))
        .add_attribute(("machine_type", pool.machine_type.as_str()))
        .add_attribute(("name", pool.name.as_str()));

    for w in &pool.workers {
        b = b.add_block(build_worker_block(w));
    }
    b.build()
}

fn build_gcp_config_block(gcp: &GcpEntry) -> hcl::Block {
    hcl::Block::builder("gcp_config")
        .add_attribute(("client_email", gcp.client_email.as_str()))
        .add_attribute(("private_key", gcp.private_key.as_str()))
        .add_attribute(("project_id", gcp.project_id.as_str()))
        .add_attribute(("zone", gcp.zone.as_str()))
        .build()
}

fn build_aws_config_block(aws: &AwsEntry) -> hcl::Block {
    hcl::Block::builder("aws_config")
        .add_attribute(("access_key_id", aws.access_key_id.as_str()))
        .add_attribute(("secret_access_key", aws.secret_access_key.as_str()))
        .add_attribute(("region", aws.region.as_str()))
        .add_attribute(("zone", aws.zone.as_str()))
        .build()
}

fn serialize_config(cfg: &MaglevConfig) -> Result<String, Box<dyn std::error::Error>> {
    let mut inner = hcl::Body::builder();

    for cp in &cfg.control_planes {
        inner = inner.add_block(build_control_plane_block(cp));
    }
    inner = inner.add_block(build_node_pool_block(&cfg.node_pool));

    inner = match &cfg.cloud {
        CloudProvider::Gcp(g) => inner.add_block(build_gcp_config_block(g)),
        CloudProvider::Aws(a) => inner.add_block(build_aws_config_block(a)),
    };

    let maglev_block = hcl::Block::builder("maglev")
        .add_label(&cfg.name)
        .add_blocks(inner.build().into_blocks())
        .build();

    let outer = hcl::Body::builder().add_block(maglev_block).build();
    Ok(hcl::to_string(&outer)?)
}

// ---------------------------------------------------------------------------
// `generate` subcommand
// ---------------------------------------------------------------------------

fn env_list(var: &str) -> Option<Vec<String>> {
    env::var(var).ok().map(|v| {
        v.split(',')
            .map(|s| s.trim().to_string())
            .filter(|s| !s.is_empty())
            .collect()
    })
}

fn generate_config(config_path: &str, force: bool) -> Result<(), Box<dyn std::error::Error>> {
    if !force && Path::new(config_path).exists() {
        eprintln!("error: '{config_path}' already exists.  Use -f / --force to overwrite.");
        std::process::exit(1);
    }

    let name = Path::new(config_path)
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("maglev")
        .to_string();

    // Decide provider from environment.
    let provider_hint = env::var("MAGLEV_PROVIDER")
        .unwrap_or_else(|_| "gcp".to_string())
        .to_lowercase();

    let cloud = if provider_hint == "aws" {
        generate_aws_entry()?
    } else {
        generate_gcp_entry()?
    };

    // ── Machine config defaults ───────────────────────────────────────────

    let (default_image, default_machine) = match &cloud {
        CloudProvider::Gcp(_) => ("ubuntu-2404-lts-amd64", "e2-standard-2"),
        CloudProvider::Aws(_) => ("ami-0c55b159cbfafe1f0", "t3.medium"),
    };

    let cp_machine_type = env::var("MAGLEV_CP_MACHINE_TYPE")
        .unwrap_or_else(|_| default_machine.to_string());
    let cp_boot_disk_image = env::var("MAGLEV_CP_BOOT_DISK_IMAGE")
        .unwrap_or_else(|_| default_image.to_string());
    let cp_boot_disk_size_gb: u64 = env::var("MAGLEV_CP_BOOT_DISK_SIZE_GB")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(50);
    let cp_ssh_public_key_path = env::var("MAGLEV_CP_SSH_PUBLIC_KEY_PATH")
        .or_else(|_| env::var("MAGLEV_SSH_PUBLIC_KEY_PATH"))
        .unwrap_or_else(|_| "~/.ssh/id_ed25519.pub".to_string());
    let cp_startup_script_path = env::var("MAGLEV_CP_STARTUP_SCRIPT_PATH")
        .unwrap_or_else(|_| "./startup-cp.sh".to_string());

    let pool_machine_type = env::var("MAGLEV_MACHINE_TYPE")
        .unwrap_or_else(|_| default_machine.to_string());
    let pool_boot_disk_image = env::var("MAGLEV_BOOT_DISK_IMAGE")
        .unwrap_or_else(|_| default_image.to_string());
    let pool_boot_disk_size_gb: u64 = env::var("MAGLEV_BOOT_DISK_SIZE_GB")
        .ok()
        .and_then(|v| v.parse().ok())
        .unwrap_or(50);
    let worker_ssh_public_key_path = env::var("MAGLEV_SSH_PUBLIC_KEY_PATH")
        .unwrap_or_else(|_| "~/.ssh/id_ed25519.pub".to_string());
    let worker_startup_script_path = env::var("MAGLEV_WORKER_STARTUP_SCRIPT_PATH")
        .unwrap_or_else(|_| "./startup.sh".to_string());

    let cp_names = env_list("MAGLEV_CP_INSTANCES")
        .unwrap_or_else(|| vec!["maglev-cp-alpha".to_string(), "maglev-cp-beta".to_string()]);

    let worker_names = env_list("MAGLEV_WORKER_INSTANCES").unwrap_or_else(|| {
        vec![
            "maglev-worker-alpha".to_string(),
            "maglev-worker-beta".to_string(),
            "maglev-worker-gamma".to_string(),
        ]
    });

    let control_planes: Vec<NodeEntry> = cp_names
        .iter()
        .map(|n| NodeEntry {
            instance_name: n.clone(),
            ssh_public_key_path: cp_ssh_public_key_path.clone(),
            startup_script_path: cp_startup_script_path.clone(),
            boot_disk_image: Some(cp_boot_disk_image.clone()),
            boot_disk_size_gb: Some(cp_boot_disk_size_gb),
            machine_type: Some(cp_machine_type.clone()),
        })
        .collect();

    let workers: Vec<NodeEntry> = worker_names
        .iter()
        .map(|n| NodeEntry {
            instance_name: n.clone(),
            ssh_public_key_path: worker_ssh_public_key_path.clone(),
            startup_script_path: worker_startup_script_path.clone(),
            boot_disk_image: None,
            boot_disk_size_gb: None,
            machine_type: None,
        })
        .collect();

    let cfg = MaglevConfig {
        name: name.clone(),
        control_planes,
        node_pool: NodePoolEntry {
            boot_disk_image: pool_boot_disk_image,
            boot_disk_size_gb: pool_boot_disk_size_gb,
            machine_type: pool_machine_type,
            name: name.clone(),
            workers,
        },
        cloud,
    };

    let hcl_text = serialize_config(&cfg)?;
    fs::write(config_path, &hcl_text)
        .map_err(|e| format!("Cannot write '{config_path}': {e}"))?;

    println!("✓ Config written to: {config_path}");
    println!("  provider            : {}", cfg.cloud.label());
    println!(
        "  control-plane nodes : {}",
        cfg.control_planes
            .iter()
            .map(|n| n.instance_name.as_str())
            .collect::<Vec<_>>()
            .join(", ")
    );
    println!(
        "  worker nodes        : {}",
        cfg.node_pool
            .workers
            .iter()
            .map(|n| n.instance_name.as_str())
            .collect::<Vec<_>>()
            .join(", ")
    );
    Ok(())
}

fn generate_gcp_entry() -> Result<CloudProvider, Box<dyn std::error::Error>> {
    let client_email = env::var("MAGLEV_CLIENT_EMAIL")
        .map_err(|_| "MAGLEV_CLIENT_EMAIL is not set")?;
    let derived_project = client_email
        .split('@')
        .nth(1)
        .and_then(|d| d.split('.').next())
        .unwrap_or("my-project")
        .to_string();
    let project_id = env::var("MAGLEV_PROJECT_ID").unwrap_or(derived_project);
    let private_key =
        env::var("MAGLEV_PRIVATE_KEY").unwrap_or_else(|_| ".keys/private_key.pem".to_string());
    let zone = env::var("MAGLEV_ZONE").unwrap_or_else(|_| "europe-north1-a".to_string());

    Ok(CloudProvider::Gcp(GcpEntry {
        client_email,
        private_key,
        project_id,
        zone,
    }))
}

fn generate_aws_entry() -> Result<CloudProvider, Box<dyn std::error::Error>> {
    let access_key_id = env::var("AWS_ACCESS_KEY_ID")
        .map_err(|_| "AWS_ACCESS_KEY_ID is not set")?;
    let secret_access_key = env::var("AWS_SECRET_ACCESS_KEY")
        .map_err(|_| "AWS_SECRET_ACCESS_KEY is not set")?;
    let region = env::var("MAGLEV_AWS_REGION")
        .or_else(|_| env::var("AWS_DEFAULT_REGION"))
        .unwrap_or_else(|_| "us-east-1".to_string());
    let zone = env::var("MAGLEV_AWS_ZONE")
        .unwrap_or_else(|_| format!("{region}a"));

    Ok(CloudProvider::Aws(AwsEntry {
        access_key_id,
        secret_access_key,
        region,
        zone,
    }))
}

// ---------------------------------------------------------------------------
// `apply` subcommand
// ---------------------------------------------------------------------------

fn apply_config(config_path: &str) -> Result<(), Box<dyn std::error::Error>> {
    println!("=== Maglev Apply ===\n");
    println!("Reading config: {config_path}");

    let content = fs::read_to_string(config_path)
        .map_err(|e| format!("Cannot read '{config_path}': {e}"))?;
    let cfg = parse_maglev_config(&content)?;
    let pool = &cfg.node_pool;

    println!("\n── Cloud settings ───────────────────────────────────────────────────────");
    println!("  Provider : {}", cfg.cloud.label());
    println!("  Zone     : {}", cfg.cloud.zone());
    match &cfg.cloud {
        CloudProvider::Gcp(g) => {
            println!("  Project  : {}", g.project_id);
            println!("  Account  : {}", g.client_email);
        }
        CloudProvider::Aws(a) => {
            println!("  Region   : {}", a.region);
            println!("  Key ID   : {}", a.access_key_id);
        }
    }

    println!(
        "\n── Control-plane nodes ({}) ─────────────────────────────────────────────",
        cfg.control_planes.len()
    );
    for cp in &cfg.control_planes {
        println!("  {:<30} ssh key: {}", cp.instance_name, cp.ssh_public_key_path);
        println!("    machine type    : {}", cp.machine_type.as_deref().unwrap_or("(pool default)"));
        println!("    boot disk image : {}", cp.boot_disk_image.as_deref().unwrap_or("(pool default)"));
        println!("    boot disk size  : {} GB", cp.boot_disk_size_gb.map(|s| s.to_string()).unwrap_or_else(|| "(pool default)".into()));
        println!("    startup script  : {}", cp.startup_script_path);
    }

    println!(
        "\n── node_pool '{}' — {} workers ──────────────────────────────────────────",
        pool.name,
        pool.workers.len()
    );
    println!("  machine type    : {}", pool.machine_type);
    println!("  boot disk image : {}", pool.boot_disk_image);
    println!("  boot disk size  : {} GB", pool.boot_disk_size_gb);
    for w in &pool.workers {
        println!("  worker  {:<30} ssh key: {}", w.instance_name, w.ssh_public_key_path);
        println!("    startup script: {}", w.startup_script_path);
    }

    let total = cfg.control_planes.len() + pool.workers.len();
    if !prompt_yes_no(&format!("\nProceed with creating {total} VM instances?")) {
        println!("Aborted.");
        return Ok(());
    }

    match &cfg.cloud {
        CloudProvider::Gcp(gcp) => apply_gcp(&cfg, gcp),
        CloudProvider::Aws(aws) => apply_aws(&cfg, aws),
    }
}

fn apply_gcp(
    cfg: &MaglevConfig,
    gcp: &GcpEntry,
) -> Result<(), Box<dyn std::error::Error>> {
    let pool = &cfg.node_pool;

    let private_key = load_gcp_private_key(gcp)?;
    println!("\n  Signing JWT...");
    let jwt = create_jwt(&private_key, &gcp.client_email, "https://www.googleapis.com/auth/compute")?;
    println!("  Exchanging JWT for access token...");
    let token = get_access_token(&jwt)?;

    for cp in &cfg.control_planes {
        println!("\n  ── Creating control-plane ({}) ──", cp.instance_name);
        let machine_type = cp.machine_type.as_deref().unwrap_or(&pool.machine_type);
        let image = cp.boot_disk_image.as_deref().unwrap_or(&pool.boot_disk_image);
        let size = cp.boot_disk_size_gb.unwrap_or(pool.boot_disk_size_gb);
        let ssh_meta = read_ssh_public_key(&cp.ssh_public_key_path)
            .map(|k| format!("ubuntu:{k}"))
            .unwrap_or_else(|e| { eprintln!("  ⚠ SSH key: {e}"); String::new() });
        let script = read_startup_script(&cp.startup_script_path);
        let resp = gcp_create_vm(&token, &gcp.project_id, &gcp.zone, &cp.instance_name,
                                  machine_type, image, size, &ssh_meta, &script)?;
        println!("{}", serde_json::to_string_pretty(&resp)?);
    }

    for w in &pool.workers {
        println!("\n  ── Creating worker ({}) ──", w.instance_name);
        let ssh_meta = read_ssh_public_key(&w.ssh_public_key_path)
            .map(|k| format!("ubuntu:{k}"))
            .unwrap_or_else(|e| { eprintln!("  ⚠ SSH key: {e}"); String::new() });
        let script = read_startup_script(&w.startup_script_path);
        let resp = gcp_create_vm(&token, &gcp.project_id, &gcp.zone, &w.instance_name,
                                  &pool.machine_type, &pool.boot_disk_image, pool.boot_disk_size_gb,
                                  &ssh_meta, &script)?;
        println!("{}", serde_json::to_string_pretty(&resp)?);
    }

    let total = cfg.control_planes.len() + pool.workers.len();
    println!("\n✓ All {total} GCP VM creation requests submitted.");
    Ok(())
}

fn apply_aws(
    cfg: &MaglevConfig,
    aws: &AwsEntry,
) -> Result<(), Box<dyn std::error::Error>> {
    let pool = &cfg.node_pool;

    for cp in &cfg.control_planes {
        println!("\n  ── Creating control-plane ({}) ──", cp.instance_name);
        let instance_type = cp.machine_type.as_deref().unwrap_or(&pool.machine_type);
        let ami = cp.boot_disk_image.as_deref().unwrap_or(&pool.boot_disk_image);
        let size = cp.boot_disk_size_gb.unwrap_or(pool.boot_disk_size_gb);
        let ssh_pub = read_ssh_public_key(&cp.ssh_public_key_path)
            .unwrap_or_else(|e| { eprintln!("  ⚠ SSH key: {e}"); String::new() });
        let script = read_startup_script(&cp.startup_script_path);
        let summary = aws_create_vm(aws, &cp.instance_name, instance_type, ami, size, &ssh_pub, &script)?;
        println!("{summary}");
    }

    for w in &pool.workers {
        println!("\n  ── Creating worker ({}) ──", w.instance_name);
        let ssh_pub = read_ssh_public_key(&w.ssh_public_key_path)
            .unwrap_or_else(|e| { eprintln!("  ⚠ SSH key: {e}"); String::new() });
        let script = read_startup_script(&w.startup_script_path);
        let summary = aws_create_vm(aws, &w.instance_name, &pool.machine_type, &pool.boot_disk_image,
                                     pool.boot_disk_size_gb, &ssh_pub, &script)?;
        println!("{summary}");
    }

    let total = cfg.control_planes.len() + pool.workers.len();
    println!("\n✓ All {total} AWS EC2 launch requests submitted.");
    Ok(())
}

